#!/usr/bin/env python3
import sys

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid + 1  # 1‑based
        elif arr[mid] > target:
            right = mid - 1
        else:
            left = mid + 1
    return -1

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        x = int(next(it))
        arr = [int(next(it)) for _ in range(n)]
        out_lines.append(str(binary_search(arr, x)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

